from typing import List

class Solution:
    def shortestSequence(self, n: int, k: int) -> str:
        # Edge case: single digit alphabet -> only password is n copies of '0'
        if k == 1:
            return "0" * n
        # Edge case: n == 1 -> every single digit must appear once
        if n == 1:
            return "".join(str(d) for d in range(k))

        start = "0" * (n - 1)
        visited = set()
        digits: List[str] = []

        def dfs(node: str) -> None:
            for d in range(k):
                edge = node + str(d)
                if edge not in visited:
                    visited.add(edge)
                    dfs(edge[1:])
                    digits.append(str(d))

        dfs(start)
        digits.reverse()
        return start + "".join(digits)


def all_passwords(n, k):
    res = set()
    def build(cur):
        if len(cur) == n:
            res.add(cur); return
        for d in range(k):
            build(cur + str(d))
    build("")
    return res

def check(n, k):
    s = Solution().shortestSequence(n, k)
    passwords = all_passwords(n, k)
    found = set(s[i:i+n] for i in range(len(s) - n + 1))
    # every password present
    assert passwords <= found, (n, k, "missing", passwords - found)
    # minimal length
    expected_len = k**n + n - 1
    assert len(s) == expected_len, (n, k, len(s), expected_len)
    return s

# samples
print("n=1,k=2:", check(1, 2))
print("n=2,k=2:", check(2, 2))

# edge cases + full constraint sweep
for n in range(1, 5):
    for k in range(1, 11):
        if k**n <= 4096:
            check(n, k)
print("All constraint combos passed (k^n <= 4096).")
print("n=1,k=1:", check(1,1))
print("n=4,k=1:", check(4,1))
print("n=4,k=8 len:", len(check(4,8)), "expected:", 8**4 + 3)

